const GRAMMAR = {"1": {"en": "Dutch has two articles: 'de' (common) and 'het' (neuter). Most nouns use 'de'. Verbs change: ik werk, jij werkt, hij werkt.", "fa": "هلندی دو حرف تعریف دارد: de و het. بیشتر اسم‌ها از de استفاده می‌کنند.", "tr": "Hollandaca'da iki tanımlık var: 'de' ve 'het'. Çoğu isim 'de' kullanır.", "ar": "في الهولندية أداتا تعريف: de و het. معظم الأسماء تستخدم de."}, "2": {"en": "'Graag' means 'gladly' and is used to say you like doing things: 'Ik zwem graag' = I like to swim.", "fa": "graag به معنی 'با میل' است: Ik zwem graag = من شنا را دوست دارم.", "tr": "'Graag' 'memnuniyetle' demektir: 'Ik zwem graag' = Yüzmeyi severim.", "ar": "graag تعني 'بسرور': Ik zwem graag = أحب السباحة."}, "3": {"en": "Adjectives before 'het' nouns don't get -e: 'het kleine kind' BUT 'een klein kind'. Before 'de' nouns always add -e: 'de grote man'.", "fa": "صفت قبل از اسم‌های het در حالت نکره e- نمی‌گیرد.", "tr": "'het' isimlerden önce belirsiz durumda sıfata -e eklenmez.", "ar": "الصفات قبل أسماء het لا تأخذ -e في حالة النكرة."}, "4": {"en": "Time expressions: 's morgens (in the morning), 's middags (afternoon), 's avonds (evening). Word order: time before place.", "fa": "عبارات زمانی: s morgens (صبح)، s middags (بعدازظهر)، s avonds (شب).", "tr": "Zaman ifadeleri: 's morgens (sabah), 's middags (öğleden sonra), 's avonds (akşam).", "ar": "تعبيرات الوقت: s morgens (صباحاً)، s middags (ظهراً)، s avonds (مساءً)."}, "5": {"en": "Quantities: 'een kilo appels', 'twee liter melk', 'een pond kaas' (500g). Use 'er' for 'of it/them': 'Ik neem er drie'.", "fa": "مقادیر: een kilo appels، twee liter melk. از er برای اشاره استفاده کنید.", "tr": "Miktarlar: 'een kilo appels', 'twee liter melk'. 'er' = ondan/onlardan.", "ar": "الكميات: een kilo appels، twee liter melk. استخدم er للإشارة."}, "6": {"en": "Travel: 'een enkele reis' (single), 'een retourtje' (return). Separable verbs: 'instappen' → 'ik stap in', 'uitstappen' → 'ik stap uit'.", "fa": "سفر: enkele reis (یک‌طرفه)، retourtje (رفت و برگشت). افعال جداشدنی: instappen → ik stap in.", "tr": "Seyahat: 'enkele reis' (tek yön), 'retourtje' (gidiş-dönüş). Ayrılabilir fiiller: instappen → ik stap in.", "ar": "السفر: enkele reis (ذهاب فقط)، retourtje (ذهاب وعودة). الأفعال المنفصلة: instappen → ik stap in."}, "7": {"en": "Describing location: 'er is/er zijn' (there is/are). Prepositions: 'op' (on), 'in' (in), 'naast' (next to), 'tussen' (between).", "fa": "توصیف مکان: er is/er zijn (وجود دارد). حروف اضافه: op، in، naast، tussen.", "tr": "Konum: 'er is/er zijn' (var/vardır). Edatlar: op (üzerinde), in (içinde), naast (yanında).", "ar": "وصف المكان: er is/er zijn (يوجد). حروف الجر: op، in، naast، tussen."}, "8": {"en": "Past tense (perfect): 'ik heb gefietst' (I cycled), 'ik ben gegaan' (I went). Use 'hebben' for most verbs, 'zijn' for movement verbs.", "fa": "زمان گذشته: ik heb gefietst (دوچرخه سواری کردم). از hebben برای بیشتر افعال و zijn برای افعال حرکتی.", "tr": "Geçmiş zaman: 'ik heb gefietst'. Çoğu fiilde 'hebben', hareket fiillerinde 'zijn' kullanılır.", "ar": "الماضي: ik heb gefietst. نستخدم hebben لمعظم الأفعال و zijn لأفعال الحركة."}, "9": {"en": "Ordering food: 'Ik wil graag...' (I would like...), 'Mag ik...?' (May I...?), 'De rekening, alstublieft' (The bill, please).", "fa": "سفارش غذا: Ik wil graag (می‌خواهم)، Mag ik...? (آیا می‌توانم؟)، De rekening alstublieft (صورتحساب لطفاً).", "tr": "Yemek siparişi: 'Ik wil graag...' (İstiyorum...), 'Mag ik...?' (Alabilir miyim?).", "ar": "طلب الطعام: Ik wil graag (أريد)، Mag ik...? (هل يمكنني؟)، De rekening alstublieft (الفاتورة من فضلك)."}, "10": {"en": "Shopping: 'Welke maat?' (What size?), 'Mag ik dit passen?' (Can I try this on?), 'Het staat u goed' (It suits you).", "fa": "خرید: Welke maat? (چه سایزی؟)، Mag ik dit passen? (می‌توانم پرو کنم؟).", "tr": "Alışveriş: 'Welke maat?' (Hangi beden?), 'Mag ik dit passen?' (Deneyebilir miyim?).", "ar": "التسوق: Welke maat? (أي مقاس؟)، Mag ik dit passen? (هل يمكنني تجربته؟)."}};

function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}

/* ═══ SOUNDS ═══ */
let soundOn=true;
function ps(f,d,v){if(!soundOn)return;try{const c=new(window.AudioContext||window.webkitAudioContext)();const o=c.createOscillator();const g=c.createGain();o.type="sine";o.frequency.value=f;g.gain.setValueAtTime(v||.12,c.currentTime);g.gain.exponentialRampToValueAtTime(.001,c.currentTime+d);o.connect(g);g.connect(c.destination);o.start();o.stop(c.currentTime+d);}catch(e){}}
function sClick(){ps(800,.12);}function sCorrect(){ps(600,.1);setTimeout(()=>ps(900,.15),100);}function sWrong(){ps(350,.3,.1);}function sStreak(){ps(500,.08);setTimeout(()=>ps(700,.08),80);setTimeout(()=>ps(1000,.12),160);}function sDone(){[440,554,659,880].forEach((f,i)=>setTimeout(()=>ps(f,.2),i*120));}

/* ═══ SPEECH ═══ */
function speakNL(word){try{const u=new SpeechSynthesisUtterance(word);u.lang="nl-NL";u.rate=0.85;speechSynthesis.speak(u);}catch(e){}}

/* ═══ STORAGE ═══ */
async function sGet(k){try{const v=localStorage.getItem('dl_'+k);return v?JSON.parse(v):null;}catch(e){return null;}}
async function sSet(k,v){try{localStorage.setItem('dl_'+k,JSON.stringify(v));}catch(e){}}
async function sGetShared(k){try{const v=localStorage.getItem('dl_shared_'+k);return v?JSON.parse(v):null;}catch(e){return null;}}
async function sSetShared(k,v){try{localStorage.setItem('dl_shared_'+k,JSON.stringify(v));}catch(e){}}

/* ═══ EXERCISE GENERATION ═══ */
function genEx(words,lang,weakWords,includeListen,includeEmoji){
  let pool=[...words];
  if(weakWords&&weakWords.length>0){const ws=new Set(weakWords);const weak=pool.filter(w=>ws.has(w.d));const strong=pool.filter(w=>!ws.has(w.d));pool=[...shuffle(weak).slice(0,8),...shuffle(strong).slice(0,6)];}
  const ws=shuffle(pool).slice(0,12);const ex=[];
  const tr=w=>lang==="en"?w.en:lang==="fa"?w.fa:lang==="tr"?w.tr:w.ar;
  // Multiple choice
  ws.slice(0,6).forEach(w=>{const oth=shuffle(words.filter(x=>x.d!==w.d)).slice(0,3).map(x=>tr(x));ex.push({type:"mc",dw:w.d,ca:tr(w),opts:shuffle([tr(w),...oth]),hint:w.d+" = "+tr(w)});});
  // Type word
  ws.slice(0,4).forEach(w=>{ex.push({type:"tw",tr:tr(w),ca:w.d,hint:'"'+w.d[0]+'..."'});});
  // Listening exercise
  if(includeListen!==false){ws.slice(0,3).forEach(w=>{const oth=shuffle(words.filter(x=>x.d!==w.d)).slice(0,3).map(x=>x.d);ex.push({type:"listen",word:w.d,ca:w.d,opts:shuffle([w.d,...oth]),hint:tr(w)});});}
  // Emoji exercise
  if(includeEmoji!==false){const emojiWords=ws.filter(w=>EMOJI[w.d]);shuffle(emojiWords).slice(0,3).forEach(w=>{const oth=shuffle(words.filter(x=>x.d!==w.d&&EMOJI[x.d])).slice(0,3).map(x=>x.d);if(oth.length>=3)ex.push({type:"emoji",emoji:EMOJI[w.d],ca:w.d,opts:shuffle([w.d,...oth]),hint:tr(w)});});}
  // Drag match
  const sw=shuffle(ws);for(let i=0;i<sw.length;i+=3){const b=sw.slice(i,i+3);if(b.length>=2)ex.push({type:"dm",pairs:b.map(w=>({d:w.d,t:tr(w)}))});}
  return shuffle(ex);
}
function genSentenceEx(sentences){if(!sentences||!sentences.length)return[];return shuffle(sentences).slice(0,3).map(s=>({type:"fb",sentence:s.s,answer:s.a,hint:s.h}));}

