const sCap=["Oopsie meow!","Try again!","Almost!","Don't give up!","Next time!","Keep going!","9 lives!"];
let gci=0,gcc2=0;
function CatReward({ok,big}){const[v]=useState(()=>{const i=gci;gci=(gci+1)%12;return i;});const[ci]=useState(()=>{const i=gcc2;gcc2++;return i;});const caps=ok?hCap:sCap;const sz=big?120:90;const bc=ok?"#58CC02":"#FF6B9D";return(<div style={{textAlign:"center",margin:"6px 0",animation:"bounceIn .4s ease-out"}}><div style={{display:"inline-block",borderRadius:12,overflow:"hidden",border:"3px solid "+bc}}><MiniCat v={v} w={sz} h={sz}/></div><p style={{fontSize:11,fontWeight:700,color:bc,marginTop:3,fontStyle:"italic"}}>{caps[ci%caps.length]}</p></div>);}

function HintBtn({hint,label,onUse}){const[show,setShow]=useState(false);if(show)return(<div style={{marginTop:10,background:"var(--c-hint-bg,#FFFDE7)",border:"2px solid #FFD54F",borderRadius:10,padding:"8px 14px",textAlign:"center",animation:"bounceIn .3s ease-out"}}><p style={{fontSize:10,fontWeight:800,color:"#F57F17",marginBottom:1}}>{"💡 "+label}</p><p style={{fontSize:13,fontWeight:600,color:"var(--c-text,#5D4037)"}}>{hint}</p></div>);return(<div style={{marginTop:10,textAlign:"center"}}><button onClick={()=>{setShow(true);if(onUse)onUse();}} style={{background:"linear-gradient(135deg,#FFF3CD,#FFECB3)",border:"2px solid #FFD54F",borderRadius:10,padding:"6px 16px",cursor:"pointer",fontSize:12,fontWeight:700,color:"#F57F17"}}>{"💡 "+label+" (-5 XP)"}</button></div>);}

function DragMatch({pairs,isRTL,ui,onDone}){const[dI]=useState(()=>shuffle(pairs.map(p=>p.d)));const[tI]=useState(()=>shuffle(pairs.map(p=>p.t)));const[m,setM]=useState({});const[sel,setSel]=useState(null);const[res,setRes]=useState(null);
  const doCheck=()=>{const r={};let ok=true;Object.entries(m).forEach(([d,t])=>{const p=pairs.find(p=>p.d===d);const c=p&&p.t===t;r[d]=c;if(!c)ok=false;});setRes(r);const cc=Object.values(r).filter(Boolean).length;setTimeout(()=>onDone(ok,cc,pairs.length),700);};
  const done=Object.keys(m).length===pairs.length;const mT=Object.values(m);
  return(<div><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:10,textAlign:"center"}}>{ui.match}</p>
    <div style={{display:"flex",gap:10,justifyContent:"center",flexWrap:"wrap"}}>
      <div style={{display:"flex",flexDirection:"column",gap:6,flex:1,minWidth:90,maxWidth:170}}>
        <div style={{fontSize:9,fontWeight:800,color:"#1CB0F6",textTransform:"uppercase",textAlign:"center"}}>Nederlands</div>
        {dI.map(w=>{const isSel=sel===w,isM=w in m,isOk=res&&res[w]===true,isBad=res&&res[w]===false;let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(isOk){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(isBad){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}else if(isSel){bg="#E3F2FD";bc="#1CB0F6";c="#0077CC";}else if(isM){bg="var(--c-muted-bg)";bc="var(--c-border)";c="var(--c-sub)";}return(<button key={w} onClick={()=>!res&&setSel(sel===w?null:w)} disabled={!!res} style={{padding:"12px 10px",minHeight:44,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:13,fontWeight:700,color:c,cursor:res?"default":"pointer",fontFamily:"'Nunito',sans-serif",transform:isSel?"scale(1.04)":"",transition:"all .15s"}}>{w}<SpeakerBtn word={w}/></button>);})}
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:6,flex:1,minWidth:90,maxWidth:170}}>
        <div style={{fontSize:9,fontWeight:800,color:"#CE82FF",textTransform:"uppercase",textAlign:"center"}}>{isRTL?"ترجمه":"Translation"}</div>
        {tI.map(w=>{const isM=mT.includes(w),canTap=sel&&!isM&&!res;const dK=Object.entries(m).find(([,v])=>v===w);const dKey=dK?dK[0]:null;let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(dKey&&res&&res[dKey]===true){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(dKey&&res&&res[dKey]===false){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}else if(canTap){bg="#FFF3E0";bc="#FFB347";c="#E65100";}else if(isM){bg="var(--c-muted-bg)";bc="var(--c-border)";c="var(--c-sub)";}return(<button key={w} onClick={()=>{if(canTap){setM(x=>({...x,[sel]:w}));setSel(null);}}} disabled={!canTap} style={{padding:"12px 10px",minHeight:44,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:13,fontWeight:700,color:c,cursor:canTap?"pointer":"default",fontFamily:"'Nunito',sans-serif",direction:isRTL?"rtl":"ltr"}}>{w}</button>);})}
      </div>
    </div>
    {Object.keys(m).length>0&&!res&&<div style={{marginTop:8}}>{Object.entries(m).map(([d,t])=>(<div key={d} style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5,padding:"4px 10px",background:"var(--c-muted-bg)",borderRadius:8,marginBottom:3,fontSize:12,fontWeight:600,color:"var(--c-sub)",border:"1px solid var(--c-border)"}}>{d} ↔ {t}<button onClick={()=>setM(x=>{const n={...x};delete n[d];return n;})} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,color:"var(--c-border)"}}>✕</button></div>))}</div>}
    {!res&&<button onClick={doCheck} disabled={!done} style={{width:"100%",padding:"12px",border:"none",borderRadius:12,marginTop:8,fontSize:14,fontWeight:800,cursor:done?"pointer":"default",background:done?"linear-gradient(135deg,#58CC02,#46A302)":"var(--c-muted-bg)",color:done?"white":"var(--c-sub)",textTransform:"uppercase",fontFamily:"'Nunito'"}}>{ui.check}</button>}
    {res&&<div style={{marginTop:8}}>{Object.entries(res).map(([d,ok])=>{const p=pairs.find(p=>p.d===d);return(<div key={d} style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5,padding:"5px 10px",borderRadius:8,marginBottom:3,background:ok?"#E8F9E0":"#FFE8E8",border:"2px solid "+(ok?"#58CC02":"#FF4B4B"),fontSize:12,fontWeight:700,color:ok?"#2E7D00":"#C00"}}>{ok?"✓":"✗"} {d} → {m[d]} {!ok&&<span style={{color:"#888",fontSize:10}}>(→{p.t})</span>}</div>);})}</div>}
  </div>);
}

/* ═══ TIMER ═══ */
function Timer({seconds,onDone}){const[left,setLeft]=useState(seconds);useEffect(()=>{if(left<=0){onDone();return;}const t=setTimeout(()=>setLeft(l=>l-1),1000);return()=>clearTimeout(t);},[left]);const m=Math.floor(left/60);const s=left%60;const pct=left/seconds*100;const urgent=left<30;return(<div style={{textAlign:"center",marginBottom:10}}><div style={{width:"100%",height:8,background:"var(--c-border)",borderRadius:99,overflow:"hidden",marginBottom:4}}><div style={{height:"100%",width:pct+"%",background:urgent?"#FF4B4B":"#1CB0F6",borderRadius:99,transition:"width 1s linear"}}/></div><span style={{fontSize:16,fontWeight:900,color:urgent?"#FF4B4B":"var(--c-text)",fontFamily:"'Nunito'"}}>{m}:{s<10?"0"+s:s}</span></div>);}

/* ═══ BADGES ═══ */
const BADGES=[{id:"first",name:"First Steps",icon:"🐱",check:p=>p.lc>=1},{id:"five",name:"Curious Cat",icon:"😺",check:p=>p.lc>=5},{id:"ten",name:"Studious Kitty",icon:"😹",check:p=>p.lc>=10},{id:"perfect",name:"Purrfect Score",icon:"🏆",check:p=>p.ps>=1},{id:"streak3",name:"On Fire",icon:"🔥",check:p=>p.sk>=3},{id:"streak7",name:"Dedicated",icon:"⭐",check:p=>p.sk>=7},{id:"allch",name:"Graduate Cat",icon:"🎓",check:p=>p.cs>=10},{id:"words100",name:"Vocab Pro",icon:"📚",check:p=>p.wl>=100},{id:"review",name:"Review Master",icon:"🔄",check:p=>p.rd>=1},{id:"poly",name:"Polyglot",icon:"🌍",check:p=>p.lu>=2},{id:"exam",name:"Exam Ace",icon:"📝",check:p=>p.ex>=1}];

