  en:{choose:"Choose the correct translation",type:"Type the Dutch word",match:"Match Dutch to English",fill:"Fill in the blank",listen:"Listen and choose the word",emojiQ:"Which Dutch word matches this?",check:"Check",next:"Continue",correct:"Purrfect!",incorrect:"Not quite!",tryAgain:"Answer",score:"Score",streak:"Streak",complete:"Lesson Complete!",restart:"Again",startLesson:"Start Lesson",selectLang:"Language",meaning:"means",greatJob:"Great job!",perfect:"Purrfect!",keepGoing:"Keep going!",hearts:"Lives",xp:"XP",hint:"Hint",selectCh:"Choose a chapter",back:"Back",wordCount:"words",review:"Review weak words",achievements:"Badges",darkMode:"Theme",sound:"Sound",dailyStreak:"streak",days:"days",locked:"Keep learning!",exam:"Exam Mode",examDesc:"Timed test across chapters",examStart:"Start Exam",examTime:"minutes",examDone:"Exam Complete!",leaderboard:"Leaderboard",lbName:"Your name",lbSubmit:"Submit",lbEmpty:"No scores yet!",grammar:"Grammar Tip",grammarShow:"Show tip"},
